sql:
SELECT le.event_name, s.speaker_name
FROM lug_events le
JOIN speakers s ON le.speaker_id = s.speaker_id;

SELECT event_id, COUNT(attendee_id) AS total_attendees
FROM event_attendance
GROUP BY event_id;

SELECT DISTINCT l.lug_name 
FROM lugs l 
JOIN lug_events le ON l.lug_id = le.lug_id;

SELECT event_id, event_name, event_date, event_start_time, event_end_time, event_type_id, event_description, speaker_id, attendance_limit, event_status
FROM lug_events
WHERE event_id = (SELECT MAX(event_id) FROM lug_events);

SELECT event_name, event_date
FROM lug_events
WHERE event_date > '2023-11-10';

SELECT lug_events.event_name, lugs.lug_name, lug_events.event_status
FROM lug_events
JOIN lugs ON lug_events.lug_id = lugs.lug_id;

external_knowledge:
- "shining stars" refers to events that stand out;
- "celebrated after November's full moon of 2022" indicates events that took place after '2022-11-10';
- "gleam of approval" metaphorically represents high ratings;
- "threshold of excellence" refers to an average rating greater than 4.
